class Solution {
    public int countSubstrings(String s) {
        int count = 0;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int mid = j;
                while (mid < n && Character.toLowerCase(s.charAt(mid)) != Character.toLowerCase(s.charAt(mid + 1))) {
                    mid++;
                }
                count += mid - i;
            }
        }
        return count;
    }
}
```

